/**
 * Custom API Error class
 */
class ApiError extends Error {
  constructor(message, statusCode, responseBody) {
    super(message);
    this.name = 'ApiError';
    this.statusCode = statusCode;
    this.responseBody = responseBody;
  }
}

/**
 * Token refresh lock to prevent concurrent refresh attempts
 */
let isRefreshing = false;
let refreshSubscribers = [];

const onTokenRefreshed = (newToken) => {
  refreshSubscribers.forEach((callback) => callback(newToken));
  refreshSubscribers = [];
};

const addRefreshSubscriber = (callback) => {
  refreshSubscribers.push(callback);
};

/**
 * Attempt to refresh the access token
 */
const refreshAccessToken = async () => {
  const refreshToken = await getRefreshToken();
  if (!refreshToken) {
    throw new ApiError('No refresh token available', 401);
  }

  const { controller, timeoutId } = createTimeoutController();

  try {
    const response = await fetch(`${BASE_URL}/auth/refresh`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Accept': 'application/json',
      },
      body: JSON.stringify({ refresh_token: refreshToken }),
      signal: controller.signal,
    });

    clearTimeout(timeoutId);

    if (!response.ok) {
      await clearTokens();
      throw new ApiError('Token refresh failed', response.status);
    }

    const data = await response.json();
    await storeTokens(data.access_token, data.refresh_token);
    return data.access_token;
  } catch (error) {
    clearTimeout(timeoutId);
    if (error.name === 'AbortError') {
      throw new ApiError('Token refresh request timed out', 408);
    }
    throw error;
  }
};

/**
 * Core fetch wrapper with authentication, retry, and error handling
 */
const apiRequest = async (endpoint, options = {}, retryCount = 0) => {
  const url = `${BASE_URL}${endpoint}`;

  // Validate URL
  if (!isValidApiUrl(url)) {
    throw new ApiError('Invalid API URL', 400);
  }

  const { controller, timeoutId } = createTimeoutController(options.timeout || REQUEST_TIMEOUT);

  const token = await getAccessToken();

  const defaultHeaders = {
    'Content-Type': 'application/json',
    'Accept': 'application/json',
    'X-Platform': Platform.OS,
    'X-Platform-Version': String(Platform.Version),
  };

  if (token) {
    defaultHeaders['Authorization'] = `Bearer ${token}`;
  }

  const config = {
    method: options.method || 'GET',
    headers: {
      ...defaultHeaders,
      ...options.headers,
    },
    signal: controller.signal,
  };

  // Only add body for non-GET/HEAD requests
  if (options.body && !['GET', 'HEAD'].includes(config.method.toUpperCase())) {
    config.body = typeof options.body === 'string' ? options.body : JSON.stringify(options.body);
  }

  try {
    const response = await fetch(url, config);
    clearTimeout(timeoutId);

    // Handle 401 - attempt token refresh
    if (response.status === 401 && retryCount === 0) {
      if (!isRefreshing) {
        isRefreshing = true;
        try {
          const newToken = await refreshAccessToken();
          isRefreshing = false;
          onTokenRefreshed(newToken);
          // Retry the original request with new token
          return apiRequest(endpoint, options, retryCount + 1);
        } catch (refreshError) {
          isRefreshing = false;
          refreshSubscribers = [];
          await clearTokens();
          throw new ApiError('Authentication expired. Please login again.', 401);
        }
      } else {
        // Wait for the ongoing refresh to complete
        return new Promise((resolve, reject) => {
          addRefreshSubscriber(async () => {
            try {
              const result = await apiRequest(endpoint, options, retryCount + 1);
              resolve(result);
            } catch (error) {
              reject(error);
            }
          });
        });
      }
    }

    // Handle rate limiting with retry
    if (response.status === 429 && retryCount < 3) {
      const retryAfter = parseInt(response.headers.get('Retry-After') || '2', 10);
      await new Promise((resolve) => setTimeout(resolve, retryAfter * 1000));
      return apiRequest(endpoint, options, retryCount + 1);
    }

    // Handle no content
    if (response.status === 204) {
      return { success: true, data: null };
    }

    // Parse response
    const contentType = response.headers.get('Content-Type') || '';
    let responseData;

    if (contentType.includes('application/json')) {
      responseData = await response.json();
    } else {
      responseData = await response.text();
    }

    if (!response.ok) {
      throw new ApiError(
        responseData?.message || `Request failed with status ${response.status}`,
        response.status,
        responseData
      );
    }

    return { success: true, data: responseData, status: response.status };
  } catch (error) {
    clearTimeout(timeoutId);

    if (error instanceof ApiError) {
      throw error;
    }

    if (error.name === 'AbortError') {
      throw new ApiError('Request timed out. Please check your connection.', 408);
    }

    // Network error - retry once for GET requests
    if (config.method === 'GET' && retryCount < 1) {
      await new Promise((resolve) => setTimeout(resolve, 1000));
      return apiRequest(endpoint, options, retryCount + 1);
    }

    throw new ApiError(
      'Network error. Please check your internet connection.',
      0,
      null
    );
  }
};

